class Solution:
    def checkMove(self, board, rMove, cMove, color):
        n = 8
        opp = 'W' if color == 'B' else 'B'
        for dr in (-1, 0, 1):
            for dc in (-1, 0, 1):
                if dr == 0 and dc == 0:
                    continue
                r, c = rMove + dr, cMove + dc
                count = 0
                ok = False
                while 0 <= r < n and 0 <= c < n:
                    cell = board[r][c]
                    if cell == opp:
                        count += 1
                    elif cell == color:
                        ok = count > 0
                        break
                    else:
                        break
                    r += dr
                    c += dc
                if ok:
                    return True
        return False

